"""
mkt-context | hosea | chapters 1-6
Run: python3 scripts/zc-context-hosea-1-6.py

Historical/ANE background commentary for Hosea 1-6.
Ch 1 v1 already exists (introductory overview); script writes v2-11 and chs 2-6.

Key decisions:
- Hosea's historical setting: northern kingdom, ca. 755-725 BCE, final decades before
  Assyria destroyed Samaria (722 BCE). Kings named in 1:1: Uzziah, Jotham, Ahaz,
  Hezekiah (Judah); Jeroboam II (Israel) = the prosperous but corrupt era.
- Marriage to Gomer: the enacted parable at the center of the book.
- "Baal" as the theological rival: Canaanite storm/fertility deity; the anti-Baal
  theology of ch 2 is the book's central polemic.
- Rib (covenant lawsuit) genre: chs 4-5 use the legal covenant-dispute form.
- Da'at (knowledge of God) = relational covenant faithfulness, not intellectual info.
- Ch 6:7 "like Adam": may be earliest prophetic use of Adamic sin typology.
"""

import json
import pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(source, book):
    path = ROOT / f"data/commentary/{source}/{book}.json"
    if path.exists():
        return json.loads(path.read_text(encoding="utf-8"))
    return {}


def save_comm(source, book, data):
    path = ROOT / f"data/commentary/{source}/{book}.json"
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")
    print(f"  wrote {path.relative_to(ROOT)}")


def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        existing.setdefault(ch, {})
        for v, html in verses.items():
            existing[ch].setdefault(v, html)


HOSEA = {
    "1": {
        "2": "<p><strong>Go and take a wife of unfaithfulness</strong> (<em>ʾeshet zenunim</em>) — the opening command is the most striking in the prophetic corpus: YHWH orders Hosea to marry a woman whose character or subsequent behavior would enact the central metaphor of the book. Scholars debate whether Gomer was already a cult prostitute, a woman with a promiscuous past, or simply someone who would prove unfaithful. The phrase <em>zenunim</em> (whoredom, unfaithfulness) is used throughout Hosea as the paradigm of covenant betrayal: Israel&rsquo;s worship of the Baals is &ldquo;playing the whore after other gods&rdquo; (Judg 2:17; 8:27). The command is simultaneously a personal commission and a prophetic sign-act — Hosea&rsquo;s marriage is the enacted word of YHWH about his own covenant relationship with Israel.</p>",
        "3": "<p><strong>Gomer daughter of Diblaim</strong> — the name Gomer may have Phoenician or Canaanite associations (a Gomer appears in the Table of Nations, Gen 10:2-3, as a northern people). <strong>Diblaim</strong> may mean &ldquo;two fig cakes,&rdquo; possibly pointing to the fertile plenty of Canaan that Israel preferred to YHWH. The historical specificity — a named woman with a named father — grounds the prophetic sign in real biography rather than allegory, lending the message its emotional and rhetorical power. Hosea&rsquo;s willingness to obey the command despite its social cost embodies the costly love he is called to preach.</p>",
        "4": "<p><strong>Name him Jezreel</strong> — Jezreel (<em>yizreʿel</em>, &ldquo;God plants&rdquo;) is freighted with historical meaning: it was the site of Jehu&rsquo;s bloody purge of the house of Ahab and the Baal worshipers (2 Kgs 9&ndash;10). YHWH had commissioned that purge through Elisha, yet now YHWH announces he will <strong>punish the house of Jehu for the bloodshed at Jezreel</strong>. The dynasty that came to power through divinely-sanctioned violence is now itself subject to judgment for the manner in which it carried out that violence. The great plain of Jezreel (also called Esdraelon) was the breadbasket of the northern kingdom and a major military theater — its significance here is both military and theological.</p>",
        "5": "<p><strong>I will break the bow of Israel in the valley of Jezreel</strong> — the bow (<em>qeshet</em>) is the primary weapon of the army; &ldquo;breaking the bow&rdquo; = military defeat (cf. Ps 46:9; Jer 49:35). The valley of Jezreel was the natural corridor through which armies moved into the highlands; control of the valley was control of the north. This oracle was fulfilled when Tiglath-pileser III of Assyria invaded and annexed significant parts of the northern kingdom in 733&ndash;732 BCE (2 Kgs 15:29), devastating the Jezreel region.</p>",
        "6": "<p><strong>Lo-ruhamah</strong> — &ldquo;Not Pitied&rdquo; or &ldquo;Not Shown Mercy&rdquo; (<em>lo ruhamah</em>); the root <em>racham</em> denotes the deep maternal compassion associated with the womb (<em>rechem</em>). YHWH&rsquo;s withdrawal of <em>rachamim</em> from Israel is the withdrawal of the most fundamental divine tenderness. The distinction between Israel (&ldquo;no longer show mercy&rdquo;) and Judah (&ldquo;I will show mercy,&rdquo; v. 7) reflects the historical reality that the northern kingdom faced Assyrian destruction while Jerusalem was spared. The name given to Hosea&rsquo;s daughter is simultaneously a theological verdict and a prophetic sign lived out in the prophet&rsquo;s own family.</p>",
        "7": "<p><strong>I will save them by the LORD their God; I will not save them by bow, sword, war, horses, or horsemen</strong> — this oracle anticipates the miraculous deliverance of Jerusalem from Sennacherib&rsquo;s siege in 701 BCE, when the Assyrian army withdrew without capturing the city after a plague struck the camp (2 Kgs 19:35&ndash;36; Isa 37:36). The explicit disclaimer of military means — bow, sword, war, horses — echoes Deuteronomy&rsquo;s warning against multiplying horses (Deut 17:16) and the Psalter&rsquo;s insistence that &ldquo;a horse is a vain hope for salvation&rdquo; (Ps 33:17). Judah&rsquo;s deliverance will be YHWH&rsquo;s act, not human military power.</p>",
        "8": "<p><strong>After she had weaned Lo-ruhamah</strong> — weaning in the ancient Near East typically occurred between two and three years of age (cf. 2 Macc 7:27; 1 Sam 1:23-24). The sequential births mark the progressive deterioration of the covenant relationship: each child&rsquo;s name carries a darker theological verdict. The time gaps between births create a sense of inexorable movement toward the final, most devastating oracle of Lo-ammi.</p>",
        "9": "<p><strong>Lo-ammi — Not My People</strong> — the most devastating of the three name-oracles: <em>lo-ammi</em> is the direct reversal of the Sinai covenant formula &ldquo;you shall be my people and I will be your God&rdquo; (Exod 6:7; Lev 26:12; Jer 11:4). YHWH is annulling the covenant in the most explicit way possible: &ldquo;you are not my people, and I am not your God&rdquo; (or possibly &ldquo;I am not &lsquo;I AM&rsquo; to you&rdquo; — <em>lo ehyeh lakhem</em>, using the divine name Ehyeh, &ldquo;I AM,&rdquo; from Exod 3:14). The covenant dissolution is expressed through the naming of a child — the most personal and permanent of acts.</p>",
        "10": "<p><strong>The number of the children of Israel will be like the sand of the sea</strong> — the reversal of Lo-ammi is expressed in the language of the Abrahamic covenant (Gen 22:17: &ldquo;I will make your offspring as numerous as the stars of heaven and as the sand that is on the seashore&rdquo;). The covenant announced to Abraham is not abolished — even the dissolution of the Mosaic covenant does not undo the Abrahamic promise. <strong>In the place where it was said to them &lsquo;You are not my people,&rsquo; it will be said to them &lsquo;Children of the living God&rsquo;</strong> — the transformation is geographical and social: in the very location of rejection comes the word of adoption. Paul reads this as applying to both restored Israel and Gentile inclusion (Rom 9:25-26).</p>",
        "11": "<p><strong>The children of Judah and Israel will be gathered together and appoint for themselves one leader</strong> — the eschatological reunification of the divided monarchy under one king reverses the schism of Jeroboam I (c. 930 BCE; 1 Kgs 12). <strong>Great will be the day of Jezreel</strong> — the site of judgment (v. 4-5) becomes the site of blessing: <em>yizreʿel</em> = &ldquo;God plants&rdquo; in its positive valence, the great day when YHWH plants his reunited people in the land. The eschatological reversal uses the same place-name for both judgment (the Jehu dynasty falls at Jezreel) and hope (YHWH plants his people at Jezreel).</p>",
    },
    "2": {
        "1": "<p><strong>Say to your brothers, &lsquo;My people,&rsquo; and to your sisters, &lsquo;My beloved&rsquo;</strong> — the reversal of Lo-ammi and Lo-ruhamah is stated immediately after the promise of restoration (1:10-11). The Hebrew is <em>ammi</em> and <em>ruhamah</em> — the names of Hosea&rsquo;s children with the negative prefix removed. This verse functions as a bridge between the oracle of judgment (ch. 1) and the extended covenant-lawsuit that follows in chapter 2: even as YHWH prosecutes Israel, the restoration is already in view.</p>",
        "2": "<p><strong>Contend with your mother, contend</strong> (<em>rivu be&rsquo;imkem rivu</em>) — the repetition signals the formal opening of a <em>rib</em> (covenant lawsuit, legal dispute). The <em>rib</em> pattern is a distinctive prophetic genre in which YHWH calls Israel to account as in a court of law, often with creation or the nations as witnesses (Mic 6:1-2; Isa 1:2-3). <strong>She is not my wife, and I am not her husband</strong> — the formal declaration of divorce using the standard ANE divorce formula (attested in Akkadian documents: &ldquo;She is not my wife; I am not her husband&rdquo;). YHWH is using the divorce proceedings of his own culture to describe the covenant dissolution, while simultaneously pleading for Gomer/Israel to remove her unfaithfulness — the divorce is not yet final.</p>",
        "3": "<p><strong>I will strip her naked and expose her as on the day she was born</strong> — in ANE legal practice, public exposure of a woman guilty of adultery or prostitution was part of the divorce and shaming process. The reversal &ldquo;as on the day she was born&rdquo; strips away all the covenant gifts YHWH gave Israel in the exodus: the clothing (metaphorical, the covenant privileges), the land, the fruitfulness. <strong>Make her like a wilderness, like a parched land</strong> — the reversal of Canaan&rsquo;s agricultural fertility back to the pre-conquest wilderness; the land&rsquo;s gifts are revealed as YHWH&rsquo;s, not the Baals&rsquo;.</p>",
        "4": "<p><strong>I will show no compassion to her children, for they are children of unfaithfulness</strong> — the children (Israel) share the identity of their mother&rsquo;s unfaithfulness. This reflects the ANE understanding of family solidarity: the household&rsquo;s guilt is shared. The theological point is not vindictive but diagnostic: a society shaped by its parents&rsquo; idolatry inherits both the practices and the consequences. The distinction from v. 3 (the mother = the nation&rsquo;s religious leadership or history?) and v. 4 (the children = the current generation?) may reflect the prophetic move from structural criticism to personal accountability.</p>",
        "5": "<p><strong>She said, &lsquo;I will go after my lovers, who give me my bread and my water, my wool and my flax, my oil and my wine&rsquo;</strong> — the <strong>lovers</strong> (<em>meʾahavim</em>) are the Baals, the Canaanite storm and fertility deities. The theological core of Baal worship was the belief that Baal controlled the rain, and therefore the grain harvest. The list — bread, water, wool, flax, oil, wine — is the standard inventory of agricultural prosperity in ancient Israel. The error is crediting the gifts to the wrong giver. Archaeological evidence from the northern kingdom shows widespread Baal worship alongside YHWH worship: Baal figurines, Asherah poles, and high-place installations have been excavated at numerous northern sites.</p>",
        "6": "<p><strong>I will block her way with thorns; I will wall her in</strong> — YHWH&rsquo;s response to Israel&rsquo;s pursuit of the Baals is to make that pursuit impossible through historical circumstances. The &ldquo;thorns&rdquo; and &ldquo;wall&rdquo; are divine obstacles — historically, the Assyrian invasions and political instability that disrupted the northern kingdom&rsquo;s prosperity and cult practices. The verb <em>sakh</em> (to hedge in) appears in Job 3:23 (God hedges in Job so he cannot move) and, positively, in Job 1:10 (God hedges Job in for protection) — the same divine action can be shelter or prison depending on one&rsquo;s orientation to YHWH.</p>",
        "7": "<p><strong>She will say, &lsquo;I will go back to my first husband, for it was better for me then than now&rsquo;</strong> — the wilderness period is idealized as the &ldquo;first marriage&rdquo; between YHWH and Israel. In the wilderness, Israel depended entirely on YHWH for manna, water, and protection; in Canaan, that dependence was transferred to the Baals. The &ldquo;first husband&rdquo; framing positions the Sinai covenant as the original marriage, and the Baal worship as adultery against it. Jeremiah 2:2 makes the same idealizing move: &ldquo;I remember the devotion of your youth, your love as a bride, how you followed me in the wilderness.&rdquo;</p>",
        "8": "<p><strong>She did not know that it was I who gave her the grain, the wine, and the oil</strong> — <strong>did not know</strong> (<em>lo yadaʿah</em>) is the central diagnostic: the &ldquo;knowledge of God&rdquo; (<em>daʿat ʾelohim</em>) that Hosea identifies as the missing element in Israel&rsquo;s relationship is precisely the recognition that YHWH is the source of all agricultural blessing. The Baal cult claimed that Baal&rsquo;s rain produced the harvest; YHWH&rsquo;s counter-claim is that he is the actual provider. <strong>Silver and gold which they used for Baal</strong> — Israel used YHWH&rsquo;s material blessings (silver and gold) to fund the cult of the Baals, the very deity credited with the blessings. The theological irony is complete.</p>",
        "9": "<p><strong>I will take back my grain when it ripens and my wine when it is ready</strong> — the grammar emphasizes YHWH&rsquo;s ownership: &ldquo;my grain,&rdquo; &ldquo;my wine&rdquo; — everything Israel attributed to Baal actually belongs to YHWH, and he can reclaim it. This is the agricultural form of covenant curse (Deut 28:30-33, 38-42): the harvest you plant will be taken from you. <strong>Uncover her nakedness before her lovers</strong> — the removal of agricultural prosperity is simultaneously the public exposure of Israel&rsquo;s shame; the fertility cult&rsquo;s failure to deliver fertility is itself the proof of Baal&rsquo;s impotence.</p>",
        "10": "<p><strong>Now I will expose her shameful nakedness before her lovers, and no one will rescue her</strong> — the ANE context of this verse is the legal public shaming of an adulteress: her lovers witness her punishment and prove powerless to help. In Israel&rsquo;s historical experience this is the Assyrian invasion: Baal could not prevent the agricultural and military catastrophe, even though Israel had burned incense to him at every high place. The claim of the fertility cult — that Baal controlled weather and military victory — is disproved precisely when Israel needed those things most.</p>",
        "11": "<p><strong>I will put an end to all her celebrations — her festivals, new moon observances, sabbaths, and all her appointed feasts</strong> — YHWH cancels Israel&rsquo;s liturgical calendar. The <em>moʿadim</em> (appointed feasts) were the three pilgrimage festivals (Passover, Weeks, Tabernacles); the <em>chodashim</em> (new moons) were monthly celebrations; the <em>shabbatot</em> (sabbaths) were the weekly marker of covenant identity. All of these had been conflated with or conducted alongside Baal worship. Their cessation means the complete collapse of the religious year. The Assyrian destruction of the northern sanctuaries (Bethel, Dan) in 722 BCE was the historical fulfillment.</p>",
        "12": "<p><strong>I will ruin her vines and her fig trees, which she said were the gifts her lovers gave her</strong> — vines and figs are the emblems of shalom in the land (1 Kgs 4:25: &ldquo;Judah and Israel lived in safety, everyone under his own vine and fig tree&rdquo;). The destruction of the vineyards and orchards — made into &ldquo;a thicket where wild animals devour&rdquo; — reverses the covenant land&rsquo;s productivity back to a pre-agricultural wilderness. This agricultural destruction was literal: Assyrian campaigns routinely cut down orchards and destroyed irrigation systems as a strategy of economic devastation (attested in Assyrian royal annals).</p>",
        "13": "<p><strong>For the days she burned incense to the Baals, adorning herself with rings and jewels and going after her lovers</strong> — the &ldquo;days of the Baals&rdquo; describes the cycle of Baal festivals, which involved elaborate preparation: the female worshiper (here Israel, metaphorically) puts on jewelry and fine clothing as she goes to the shrine. The rings and jewels may indicate either the adornment of cult images or the worshipers themselves at the high-place festivals. The phrase <em>vatishkacheni neʾum YHWH</em> — &ldquo;she forgot me, declares the LORD&rdquo; — is the theological core: the sin is not ignorance but willful forgetting, the active suppression of the covenant memory.</p>",
        "14": "<p><strong>Therefore, behold, I will allure her and bring her into the wilderness and speak tenderly to her</strong> — the divine response to Israel&rsquo;s unfaithfulness is not only judgment but a second courtship. The wilderness (<em>midbar</em>) is the place of YHWH&rsquo;s original relationship with Israel (the Sinai period), before Canaan&rsquo;s prosperity led to Baal worship. &ldquo;Speak tenderly&rdquo; (<em>dibarti ʿal-libah</em>, &ldquo;speak to her heart&rdquo;) is the language of courtship (Gen 34:3; Ruth 2:13; Judg 19:3). The exile — which stripped Israel of land, temple, and king — is reinterpreted as a divinely-arranged wilderness for a new covenant relationship.</p>",
        "15": "<p><strong>There I will give back her vineyards and make the Valley of Achor a door of hope</strong> — the Valley of Achor (&ldquo;Valley of Trouble&rdquo;) was where Achan was executed for covenant violation after the conquest (Josh 7:24-26); it became proverbial for the consequence of betrayal. YHWH promises to transform the very symbol of covenant judgment into <strong>a door of hope</strong>: the entry-point into the land (the Jordan valley area) that was the scene of covenant failure becomes the entry-point of restoration. The vineyard restoration reverses v. 12. <strong>She will respond there as in the days of her youth, as in the day she came out of Egypt</strong> — the second exodus theme: Israel will respond to YHWH&rsquo;s renewed courtship as she responded at Sinai.</p>",
        "16": "<p><strong>You will call me &lsquo;My Husband&rsquo; (<em>ishi</em>) and will no longer call me &lsquo;My Master&rsquo; (<em>baali</em>)</strong> — this verse is built on a Hebrew wordplay. <em>Ishi</em> means &ldquo;my husband/my man&rdquo; (the intimate partner); <em>baali</em> means &ldquo;my lord/master&rdquo; and is also the name of the Canaanite god Baal. Israel calling YHWH &ldquo;my Baal&rdquo; as a title of lordship had become indistinguishable from invoking the name of the rival deity. The eschatological restoration removes this ambiguity: the covenant relationship will be so intimate that Israel will address YHWH with the most personal term for a husband, not a term confusable with Baal&rsquo;s name.</p>",
        "17": "<p><strong>I will remove the names of the Baals from her mouth, and they will be mentioned no more</strong> — the elimination of the Baal names from Israel&rsquo;s liturgical vocabulary is part of the covenant renewal. Personal names compounded with &ldquo;Baal&rdquo; were common in the early monarchy (Saul&rsquo;s son Ish-baal; David&rsquo;s son Beeliada; 1 Chr 8:33; 14:7) and were later systematically changed in the text to &ldquo;bosheth&rdquo; (shame) — e.g., Ish-bosheth, Mephibosheth. The Deuteronomic reform under Josiah systematically destroyed Baal installations and removed the names from the cult; Hosea anticipates this as ultimately a divine act rather than a royal program.</p>",
        "18": "<p><strong>In that day I will make a covenant for them with the wild animals, the birds of the sky, and the creatures that crawl on the ground</strong> — the new covenant extends to the whole created order, reversing the curse on creation (Gen 3:14-19; 9:2). The hostility between humans and animals introduced at the fall is overcome; <strong>I will abolish the bow, the sword, and warfare from the land, and make them lie down in safety</strong> — the elimination of weapons recalls the eschatological vision of Isaiah 2:4 (beating swords into plowshares) and Micah 4:3. The new covenant inaugurates a creation-wide shalom that the Sinai covenant could not produce because it was constantly violated.</p>",
        "19": "<p><strong>I will betroth you to me forever; I will betroth you in righteousness and justice, in covenant loyalty and compassion</strong> — the triple betrothal formula is unique in the Hebrew Bible. <strong>Righteousness and justice</strong> (<em>tsedek umishpat</em>) = the juridical foundations of the relationship; <strong>covenant loyalty and compassion</strong> (<em>hesed werahamim</em>) = the relational qualities that sustain it. The five terms of vv. 19-20 — tsedek, mishpat, hesed, rahamim, emunah — together describe the full character of YHWH&rsquo;s covenant commitment. This is the covenant that human failure could not maintain being re-established on the basis of YHWH&rsquo;s own qualities rather than Israel&rsquo;s performance.</p>",
        "20": "<p><strong>I will betroth you in faithfulness, and you will know the LORD</strong> — <em>emunah</em> (faithfulness, steadiness) is the fifth betrothal quality, and the climax is: <em>weyadaʿat ʾet-YHWH</em>, &ldquo;you will know YHWH.&rdquo; The <em>daʿat</em> (knowledge) that Hosea identified as the fatal absence in ch. 4 (&ldquo;destroyed for lack of knowledge&rdquo;; &ldquo;no knowledge of God in the land&rdquo;) will be the defining feature of the new covenant. The new relationship will be characterized by the very thing the old relationship lacked. Jeremiah 31:34 develops this theme: in the new covenant, everyone will know YHWH from the least to the greatest.</p>",
        "21": "<p><strong>In that day I will respond to the heavens, and they will respond to the earth</strong> — a cosmic chain of response (<em>ʿanah</em>, to answer/respond): YHWH answers the heavens, the heavens answer the earth, the earth answers the grain/wine/oil, the grain/wine/oil answers Jezreel. This reverses the covenant curse where the heavens &ldquo;shut up&rdquo; their rain (Deut 28:24; 1 Kgs 17:1). The chain of divine-natural responsiveness describes a universe working as YHWH designed it, with every level of creation in harmonious response to the one above it, ultimately responsive to YHWH himself.</p>",
        "22": "<p><strong>The earth will respond to the grain, the wine, and the oil, and they will respond to Jezreel</strong> — the chain of response concludes with <em>Jezreel</em> (&ldquo;God plants&rdquo;), the name that carries both judgment (1:4-5) and restoration (1:11; 2:22). The name is now fully positive: the cosmic food chain is responsive to the place where God plants his people. The agricultural restoration concretizes the eschatological promise: the same crops that Israel credited to Baal will flow from YHWH&rsquo;s renewed covenant in the land.</p>",
        "23": "<p><strong>I will plant her for myself in the land, and I will show mercy to Lo-ruhamah, and to Lo-ammi I will say &lsquo;You are my people,&rsquo; and he will say &lsquo;You are my God&rsquo;</strong> — the three children&rsquo;s names are reversed: Israel is planted in the land (Jezreel = God plants), Lo-ruhamah becomes Ruhamah (pitied), Lo-ammi becomes Ammi (my people). The covenant formula &ldquo;You are my people / You are my God&rdquo; — the same formula whose dissolution was the most devastating moment of ch. 1:9 — is fully restored. Paul applies this restoration to Gentile inclusion (Rom 9:25-26); Peter applies it to the church (1 Pet 2:10).</p>",
    },
    "3": {
        "1": "<p><strong>Go again, love a woman who is loved by another man and is an adulteress</strong> — the second act of the marriage drama. Whether this is Gomer returned or another woman is debated; most interpreters identify her with Gomer. The command to love a woman who is currently with another man is the enacted parable of YHWH&rsquo;s love for Israel during the period of Baal apostasy: <strong>even as the LORD loves the children of Israel, though they turn to other gods</strong>. The word <em>ʾahav</em> (love) here is covenantal love — the same love that established the relationship is the love that pursues the unfaithful. The <strong>raisin cakes</strong> (<em>ʾashishe anavim</em>) were associated with Baal-Asherah festival offerings (cf. Jer 7:18; 44:19), indicating Israel&rsquo;s current cultic location.</p>",
        "2": "<p><strong>So I bought her back for fifteen pieces of silver and a homer and a half of barley</strong> — the payment to redeem Gomer suggests she had sold herself into some form of debt-slavery or servitude to a paramour. The standard price for a slave was thirty pieces of silver (Exod 21:32; Zech 11:12-13). Fifteen silver plus a homer and a half of barley (whose monetary value may equal fifteen silver) = the full slave price; or the amount reflects the degraded market value of this particular woman. The act of buying back one&rsquo;s own wife who had been sold to another is both humiliating and costly — the price of covenant love when it pursues those who have abandoned it.</p>",
        "3": "<p><strong>You must stay with me for many days; you are not to be a prostitute or to be with any man, and I also will be faithful to you</strong> — Hosea imposes a period of sexual exclusivity on Gomer that mirrors the waiting period Israel will experience before restoration. The phrase <em>wĕgam-ʾanî ʾelaik</em> (&ldquo;and I also will be to you&rdquo;) expresses YHWH&rsquo;s reciprocal faithfulness during Israel&rsquo;s period of exile and deprivation. The relationship is suspended but not dissolved; the waiting is a structured preparation for renewal rather than permanent rejection.</p>",
        "4": "<p><strong>The children of Israel will live for many days without a king, without a ruler, without a sacrifice, without a sacred pillar, without an ephod or household gods</strong> — this verse describes the condition of Israel in exile and diaspora after 722 BCE with remarkable precision. <strong>Without a king</strong>: the monarchy ended with the Assyrian conquest; <strong>without a sacrifice</strong>: the temple and official cult sites were destroyed; <strong>without a sacred pillar</strong> (<em>matstsevah</em>): the standing stone used in both Yahwistic and Canaanite worship was removed; <strong>without an ephod</strong>: the priestly oracle device; <strong>without household gods</strong> (<em>teraphim</em>): the private family cult objects. The entire structure of Israelite religious and political life is dismantled — but the implied point is that this stripping away is the preparation for pure, undistracted covenant renewal.</p>",
        "5": "<p><strong>Afterward the children of Israel will return and seek the LORD their God and David their king</strong> — the eschatological restoration unites the two halves of Israel&rsquo;s national aspiration: covenant relationship with YHWH and Davidic kingship. <strong>David their king</strong> does not mean David personally returned, but a Davidic Messiah — the same figure Ezekiel calls &ldquo;my servant David&rdquo; (Ezek 34:23-24; 37:24-25) and Jeremiah calls &ldquo;David their king&rdquo; (Jer 30:9). <strong>In the latter days</strong> (<em>beʾacharit hayyamim</em>) is the standard formula for the eschatological horizon — the fulfillment lies beyond Israel&rsquo;s historical present in the messianic age.</p>",
    },
    "4": {
        "1": "<p><strong>For the LORD has a case (<em>rib</em>) against the inhabitants of the land</strong> — chapter 4 opens the formal covenant-lawsuit section of Hosea (chs. 4-5). The <em>rib</em> is a legal genre in which YHWH summons Israel before a cosmic court (with creation or the nations as witnesses) and presents charges. Micah 6:1-2 and Isaiah 1:2-3 use the same form. The three missing covenant qualities named — <strong>no faithfulness (<em>emet</em>), no steadfast love (<em>hesed</em>), no knowledge of God (<em>daʿat ʾelohim</em>)</strong> — are exactly the three terms that define Israel&rsquo;s covenant identity. Their absence is the evidence for the prosecution.</p>",
        "2": "<p><strong>There is cursing, lying, murder, stealing, and adultery; they break all bounds, and bloodshed follows bloodshed</strong> — the five sins roughly correspond to violations of Decalogue commandments six through nine (murder, false witness, theft, adultery) plus false oaths. The phrase <strong>bloodshed follows bloodshed</strong> (<em>damim bedamim nagaʿu</em>) = violence is so pervasive that one violent act immediately produces another; the social fabric has collapsed. Archaeological evidence from the late 8th-century northern kingdom shows political instability: six kings in the last twenty-five years of the kingdom, four by assassination (2 Kgs 15).</p>",
        "3": "<p><strong>Therefore the land mourns, and all who live in it waste away — the animals, the birds, and the fish of the sea</strong> — covenant sin has ecological consequences: the land itself mourns (<em>ʾaval</em>) and the animal kingdom shares in the disaster. This is one of the earliest expressions of what might be called covenant ecology: the created order is bound together with Israel&rsquo;s covenant fidelity; when the covenant is violated, creation suffers (cf. Gen 3:17-19; Jer 12:4; Joel 1:10-12; Rom 8:20-22). The fish of the sea is an unusual inclusion — extending the covenant&rsquo;s ecological reach to the deepest domains.</p>",
        "4": "<p><strong>Let no one accuse or rebuke another, for your people are like those who bring charges against a priest</strong> — the social and religious authority structures have collapsed so completely that there is no credible basis for moral critique; the accusers are as guilty as the accused. The comparison to <strong>bringing charges against a priest</strong> may indicate that even the priestly office — which should have been the basis for moral instruction — has been so corrupted that it offers no higher standard. Alternatively: your people behave as defiantly as if they were rebelling against the priestly authority itself.</p>",
        "5": "<p><strong>You stumble in the daylight; the prophet stumbles with you in the night</strong> — stumbling in daylight, when one should be able to see clearly, is even more damning than stumbling at night. The moral blindness is so profound that the prophet who should provide night-vision (prophetic guidance through dark times) also stumbles. The double failure of priestly instruction (v. 6) and prophetic guidance (v. 5) means Israel has lost all its divinely-appointed navigational aids. <strong>I will destroy your mother</strong> = the nation as a whole; the &ldquo;mother&rdquo; is corporate Israel whose leadership failures bring collective judgment.</p>",
        "6": "<p><strong>My people are destroyed for lack of knowledge (<em>daʿat</em>)</strong> — <em>daʿat ʾelohim</em> (knowledge of God) in Hosea is not intellectual information but relational covenant faithfulness — the intimate &ldquo;knowing&rdquo; between YHWH and Israel that sustains the covenant relationship (cf. 2:20: &ldquo;you will know the LORD&rdquo;). The priest&rsquo;s primary function was to teach Torah (Deut 33:10; Mal 2:7); by <strong>rejecting knowledge</strong> (<em>maʾasta haddaʿat</em>), the priests had abandoned their vocational identity. <strong>I will reject you from being a priest to me</strong> — the punishment mirrors the crime: you rejected the priestly function, YHWH rejects you from the priestly office. <strong>Since you have forgotten the Torah of your God, I also will forget your children</strong> — the generational consequence of priestly failure.</p>",
        "7": "<p><strong>The more they multiplied, the more they sinned against me; they exchanged their glory for something shameful</strong> — Israel&rsquo;s prosperity under Jeroboam II (ca. 786-746 BCE) was a period of territorial expansion and economic growth (2 Kgs 14:25-28) that paradoxically produced more, not less, apostasy. The greater the wealth, the greater the tribute paid to the Baals credited with it. <strong>Exchanged their glory (<em>kavod</em>) for something shameful</strong> — the glory is YHWH himself, as Paul notes: the fundamental human problem is exchanging &ldquo;the glory of the immortal God for images&rdquo; (Rom 1:23). The Masoretic scribes changed the text to &ldquo;their glory&rdquo; (from &ldquo;my glory&rdquo;), a scribal emendation to avoid saying YHWH was exchanged for shameful things.</p>",
        "8": "<p><strong>They feed on the sins of my people; they are greedy for their iniquity</strong> — a devastating economic critique: the priests derive their income from sin offerings (Lev 6:26; 7:7-10), so a system of corrupt priests has a financial incentive for high sin rates. When the priestly system is corrupt, the priests benefit materially from the people&rsquo;s continued sinning rather than seeking their repentance and restoration. This conflict of interest between priestly income and prophetic mission explains the structural corruption Hosea diagnoses in the religious leadership.</p>",
        "9": "<p><strong>And it will be: like people, like priest</strong> (<em>wehayah keʿam kekohen</em>) — one of the most memorable aphorisms in the prophetic literature: the moral level of the leadership exactly mirrors the moral level of the people, and vice versa. When the priesthood is corrupt, the people follow; when the people are corrupt, the priesthood both reflects and enables it. The circular causation means the entire system must be judged rather than reform being applied from one level. <strong>I will punish them for their ways and repay them for their deeds</strong> — the priestly class has no exemption from covenant accountability; their office confers greater responsibility, not immunity.</p>",
        "10": "<p><strong>They will eat but not be satisfied; they will pursue prostitution but not flourish, because they have abandoned the LORD</strong> — the covenant curse of frustrated abundance (Lev 26:26; Deut 28:38-44): eating without satisfaction, working without result. The specific application to <strong>pursuing prostitution</strong> covers both cultic prostitution at the Baal shrines and the metaphorical prostitution of Baal worship itself. The theological logic: the fertility cult that promises agricultural and sexual abundance actually produces the opposite. YHWH withholds the blessing that Baal falsely claims to provide.</p>",
        "11": "<p><strong>Prostitution, wine, and new wine take away the understanding (<em>lev</em>)</strong> — <em>lev</em> (heart, mind, understanding) is the center of moral and cognitive life in Hebrew anthropology. The cult practices at the Baal high places involved ritual drinking and sexual activity (cf. Amos 2:8; Exod 32:6), which Hosea identifies as systematically destroying the capacity for moral judgment. The connection between intoxication and cultic sexuality was characteristic of Canaanite fertility festivals documented in Ugaritic texts (14th-12th century BCE).</p>",
        "12": "<p><strong>My people consult a piece of wood (<em>ets</em>), and their divining rod gives them answers</strong> — <em>ets</em> (wood, tree) refers to carved wooden idols or Asherah poles; the &ldquo;divining rod&rdquo; (<em>maqlam</em>) is rhabdomancy — using sticks to obtain oracles, attested in Mesopotamian and Canaanite divination practice. <strong>A spirit of prostitution has led them astray</strong> (<em>ruach zenunim</em>) — Hosea personifies the power of apostasy as a spirit that has possessed Israel, redirecting its fundamental orientation from YHWH to the Baals. <strong>They have left their God to pursue prostitution</strong> — the verb <em>zanah</em> (to play the whore) is used for both literal sexual immorality and the metaphorical abandonment of the covenant.</p>",
        "13": "<p><strong>They sacrifice on the mountaintops and burn incense on the hills, under oak and poplar and terebinth trees</strong> — the high-place (<em>bamah</em>) worship is archaeologically well-attested: elevated sites, often on hilltops, with standing stones (<em>matstsevot</em>), Asherah poles, and altars. The specific trees named — oak, poplar, terebinth — were associated with Canaanite sacred sites where shade provided cover for cultic activities. Deuteronomy 12:2 commands the destruction of these sites: &ldquo;You shall tear down their altars... and hew down the carved images of their gods and destroy their name out of that place.&rdquo; <strong>Because their shade is good</strong> — the practical reason for locating cult at shaded hilltops; the sacred and the practical are interwoven.</p>",
        "14": "<p><strong>I will not punish your daughters when they commit prostitution, or your daughters-in-law when they commit adultery, because the men themselves go aside with prostitutes and sacrifice with cult prostitutes</strong> — a remarkable reversal of the standard ancient Near Eastern double standard that held women far more accountable for sexual immorality than men. YHWH refuses to punish women for behavior that the men participate in equally or more. The <em>qedeshot</em> (cult prostitutes, sacred women at the Baal shrines) were part of the Canaanite fertility cult infrastructure. <strong>A people without understanding will come to ruin</strong> — the echo of &ldquo;take away understanding&rdquo; in v. 11; a people that has deliberately destroyed its capacity for moral judgment is self-destructing.</p>",
        "15": "<p><strong>Though you, Israel, commit adultery, do not let Judah become guilty. Do not go to Gilgal or up to Beth-aven</strong> — Hosea addresses Judah with a warning not to imitate the northern kingdom. <strong>Gilgal</strong> was a major cult site in the Jordan valley (cf. Amos 4:4; 5:5); <strong>Beth-aven</strong> (&ldquo;house of vanity/wickedness&rdquo;) is a derogatory name for Bethel (&ldquo;house of God&rdquo;), where Jeroboam I had installed the golden calves (1 Kgs 12:28-29). The renaming of Bethel as Beth-aven is prophetic commentary on the corruption of the site. <strong>Do not swear &lsquo;As the LORD lives&rsquo;</strong> — oaths invoking YHWH&rsquo;s name had become formulaic and false, part of the general decline of covenant language into meaninglessness.</p>",
        "16": "<p><strong>For Israel has become stubborn like a stubborn heifer</strong> (<em>parah sorerah</em>) — the image of the unbroken heifer refusing the yoke is a precise metaphor for Israel&rsquo;s refusal of YHWH&rsquo;s instruction (<em>Torah</em>). The yoke was the standard metaphor for covenant obligation; the stubborn animal that kicks against the yoke is the animal that cannot be herded into the safety of the fold. <strong>Can the LORD now pasture them like a lamb in open country?</strong> — the rhetorical question implies no: a stubborn heifer cannot be treated with the gentle care appropriate to a lamb. The protective shepherd relationship requires the sheep&rsquo;s responsiveness.</p>",
        "17": "<p><strong>Ephraim is joined to idols; leave him alone</strong> (<em>chabar ʿatsabbim Ephrayim hannach lo</em>) — one of the most chilling divine declarations in the prophetic literature: YHWH announces his withdrawal from Ephraim. The phrase <em>hannach lo</em> (&ldquo;let him alone&rdquo;) is the divine abandonment: when a person or nation has made their final choice for idolatry, YHWH respects that choice by withdrawing. This is the theological pattern Paul describes in Romans 1:24, 26, 28: &ldquo;God gave them over&rdquo; — divine passivity that allows the consequences of chosen idolatry to run their course.</p>",
        "18": "<p><strong>Their drinking bouts are over; they have given themselves completely to prostitution</strong> — the orgiastic cult celebrations that defined the northern kingdom&rsquo;s religious life have culminated in total moral degradation. <strong>Their rulers dearly love shame</strong> (<em>ʾohavu havu qalonah</em>) — the political leadership has become so thoroughly corrupt that it actively embraces shameful behavior; shame has lost its social corrective function when the leaders value it.</p>",
        "19": "<p><strong>A wind will sweep them away in its wings, and they will be ashamed of their sacrifices</strong> — the &ldquo;wind&rdquo; (<em>ruach</em>) is the Assyrian army, which swept over the northern kingdom like a great wind. The Assyrian military campaigns of Tiglath-pileser III (733-732 BCE) and Shalmaneser V/Sargon II (722 BCE) are the historical referent. <strong>Ashamed of their sacrifices</strong> — when the Baals fail to prevent the Assyrian conquest, the futility of the entire fertility cult is exposed: the gods who supposedly provided agricultural abundance and military protection have delivered neither.</p>",
    },
    "5": {
        "1": "<p><strong>Hear this, O priests! Listen, O house of Israel! Give ear, O house of the king!</strong> — chapter 5 addresses the entire leadership triad: priests (religious), people (corporate Israel), and king (political). The escalating address draws each level of society into the covenant lawsuit. <strong>For judgment is coming against you; you have been a snare at Mizpah, a net spread upon Tabor</strong> — Mizpah was both a judicial center and a shrine; Tabor was a mountain with pagan associations. The places where Israel should have found justice and worship have become traps for the people.</p>",
        "2": "<p><strong>The rebels are deep in their corruption; though I have been a discipline to all of them</strong> — <em>shachatu</em> (deep corruption, slaughter) describes the thoroughness of the apostasy; the word suggests a pit dug as a trap. Despite YHWH&rsquo;s repeated disciplinary actions in history — drought, plague, enemy invasion, political instability — the leadership has only deepened its rebellion. The history of the northern kingdom from Jeroboam I to the final kings is a history of YHWH&rsquo;s warnings going unheeded.</p>",
        "3": "<p><strong>I know Ephraim, and Israel is not hidden from me</strong> — divine omniscience (<em>daʿat</em> again — YHWH &ldquo;knows&rdquo; in the same full relational sense Israel refuses to know him). The claim that Israel&rsquo;s unfaithfulness is hidden — perhaps by the proliferation of cult sites that blended YHWH and Baal worship — is categorically rejected. <strong>Ephraim, you have now played the whore; Israel is defiled (<em>tame</em>)</strong> — ritual impurity (<em>tumeʾah</em>) that prevents access to YHWH&rsquo;s presence; the nation has made itself ritually incapable of approaching the very deity it supposedly worships at the shrines.</p>",
        "4": "<p><strong>Their deeds do not permit them to return to their God; a spirit of prostitution is within them, and they do not know the LORD</strong> — the <em>ruach zenunim</em> (spirit of prostitution, cf. 4:12) has become so embedded in Israel&rsquo;s corporate character that repentance is practically impossible — not because YHWH refuses it but because the nation&rsquo;s habits of mind and practice have foreclosed it. The &ldquo;knowledge of God&rdquo; — the relational covenant intimacy — is absent precisely because Israel&rsquo;s practices have substituted everything else for it. Paul describes the same dynamic in Romans 1: when humans suppress the truth about God, the suppression becomes self-reinforcing.</p>",
        "5": "<p><strong>Israel&rsquo;s arrogance (<em>gaʾon Yisraʾel</em>) testifies against him to his face</strong> — <em>gaʾon</em> (pride, arrogance) is the attitude that makes repentance impossible: the refusal to acknowledge dependence on YHWH. The same phrase &ldquo;pride of Israel&rdquo; appears in Amos 8:7 as a divine oath (YHWH swears by &ldquo;the pride of Jacob&rdquo; = himself, or ironically by Israel&rsquo;s arrogance). Israel and Judah both stumble in their iniquity — the southern kingdom is also implicated, perhaps in the context of the Syro-Ephraimite war (735 BCE), when Judah allied with Assyria rather than trusting YHWH (Isa 7-8).</p>",
        "6": "<p><strong>They will go with their flocks and herds to seek the LORD, but they will not find him; he has withdrawn from them</strong> — the bringing of sacrificial animals is the conventional form of seeking YHWH&rsquo;s favor, but the ritual is futile when it masks the absence of genuine covenant faithfulness. <strong>He has withdrawn from them</strong> (<em>chalats mibbahem</em> — he has removed himself) — the divine withdrawal as judgment. This is the condition described in Lamentations 3:8 (&ldquo;when I call and cry for help, he shuts out my prayer&rdquo;) and contrasts with Deuteronomy 4:29 which promises that genuine seeking in exile will find YHWH — but genuine seeking involves the &ldquo;acknowledgment of guilt&rdquo; that v. 15 specifies.</p>",
        "7": "<p><strong>They have been unfaithful to the LORD, because they have borne illegitimate children</strong> (<em>banim zarim</em>, &ldquo;strange/foreign children&rdquo;) — children of the Baal unions (both literal offspring of cultic sexual activity and metaphorical descendants who are spiritually foreign to YHWH&rsquo;s covenant). <strong>Now the new moon will devour them along with their fields</strong> — the new moon festival (which should be a celebration of covenant renewal) becomes an instrument of judgment. The irony: the liturgical calendar Israel has perverted turns against them.</p>",
        "8": "<p><strong>Sound the ram&rsquo;s horn in Gibeah, the trumpet in Ramah; raise the battle cry at Beth-aven</strong> — Gibeah, Ramah, and Beth-aven are in Benjamin and at the border between the northern and southern kingdoms. The alarm call suggests an imminent military invasion from the south (Judah, allied with Assyria?) or the Assyrian advance. The archaic battle cry <strong>&ldquo;Behind you, Benjamin!&rdquo;</strong> (<em>ʾachareka Binyamin</em>) may be a quotation from the Song of Deborah (Judg 5:14) or a standard military rally call — its archaism heightens the urgency of the warning.</p>",
        "9": "<p><strong>Ephraim will be laid waste on the day of punishment; among the tribes of Israel I have declared what is certain</strong> — the &ldquo;day of punishment&rdquo; (<em>yom tokechah</em>) is the divinely-appointed judgment; &ldquo;what is certain&rdquo; (<em>neʾemanah</em>, faithful/reliable) emphasizes that the oracle is not contingent but fixed. This certainty language is characteristic of Hosea&rsquo;s judgment oracles in the final chapters of the northern kingdom&rsquo;s existence: the point of no return has been passed.</p>",
        "10": "<p><strong>The princes of Judah have become like those who move boundary stones</strong> — moving boundary stones (<em>magge migsug gĕvul</em>) was the most basic violation of property rights in ancient Israel; it was explicitly cursed in Deuteronomy 27:17 and Proverbs 22:28; 23:10. The princes of Judah are accused of territorial aggression, probably in the context of the Syro-Ephraimite crisis (735 BCE), when Judah&rsquo;s expansion or political maneuvering violated established boundaries. <strong>I will pour out my wrath on them like water</strong> — the divine judgment is as unstoppable and overwhelming as a flood.</p>",
        "11": "<p><strong>Ephraim is oppressed and crushed in justice, because he was determined to pursue worthless idols</strong> — the word translated &ldquo;worthless idols&rdquo; or &ldquo;filth&rdquo; (<em>tsav</em>) may refer to a specific Baal idol or simply to idolatrous practices in general. The oppression and crushing is both the divine judgment and the historical Assyrian pressure. The phrase &ldquo;determined to pursue&rdquo; (<em>yahel halakh ʾachar tsav</em>, &ldquo;he was stubborn to walk after vanity&rdquo;) emphasizes willful persistence in the face of repeated warnings.</p>",
        "12": "<p><strong>I will be like a moth to Ephraim and like rot to the house of Judah</strong> — YHWH as slow internal destruction rather than sudden military defeat. The moth that silently eats the garment and the rot that gradually destroys wood are agents of invisible, cumulative decay. This contrasts with the lion imagery in vv. 14-15: YHWH can act as the hidden agent of dissolution or the sudden agent of catastrophe. The slow decay corresponds to the internal political instability of both kingdoms in the mid-8th century BCE.</p>",
        "13": "<p><strong>When Ephraim saw his sickness and Judah saw his wound, Ephraim turned to Assyria and sent to the great king</strong> — the historical anchor: Menahem of Israel paid tribute to Tiglath-pileser III of Assyria (745-727 BCE; 2 Kgs 15:19-20) in exchange for political support. Ahaz of Judah also appealed to Assyria for help against the Syro-Ephraimite coalition (2 Kgs 16:7-9). <strong>The great king</strong> (<em>melek yarev</em>) may be a title (Assyrian kings used &ldquo;great king&rdquo; as a royal title in their inscriptions) or a personal name. <strong>But he cannot heal you or cure your wound</strong> — the theological verdict: Assyria can temporarily relieve political pressure but cannot address the covenant wound that is the real sickness.</p>",
        "14": "<p><strong>For I will be like a lion to Ephraim, like a young lion to the house of Judah; I myself will tear them apart and go away</strong> — the divine-warrior-as-predator imagery: YHWH tears and withdraws, leaving his prey to lie wounded. The lion was the most fearsome predator in the ancient Near East and a common symbol of royalty and divine power (cf. Amos 3:8; Rev 5:5). The withdrawal after tearing — <strong>I will carry off and no one shall rescue</strong> — describes the completeness of the Assyrian deportation: the northern kingdom&rsquo;s population was scattered and no power could restore them.</p>",
        "15": "<p><strong>I will return to my place until they acknowledge their guilt and seek my face; in their distress they will earnestly seek me</strong> — YHWH announces withdrawal to &ldquo;his place&rdquo; (<em>mĕqomi</em>) with a condition for return: <em>yiʾshemu</em> (acknowledge their guilt, literally &ldquo;bear their guilt&rdquo;) and genuine seeking of YHWH&rsquo;s face. This is the pattern of divine hiddenness that the prophets consistently treat as the prelude to restoration: authentic repentance arising from &ldquo;distress&rdquo; (<em>batstsar lahem</em>) rather than ritual seeking (v. 6). Jesus enacts the same pattern in Matthew 23:39: he withdraws from Jerusalem, conditioning his visible return on Israel saying &ldquo;Blessed is he who comes in the name of the Lord.&rdquo;</p>",
    },
    "6": {
        "1": "<p><strong>Come, let us return to the LORD; he has torn us, but he will heal us; he has wounded us, but he will bind up our wounds</strong> — chapter 6 opens with what appears to be a penitential psalm; many scholars identify it as Israel&rsquo;s shallow repentance that YHWH&rsquo;s response in vv. 4-6 rejects. The logic of vv. 1-3 (&ldquo;he has torn us, but he will heal us&rdquo;) moves too quickly from judgment to restoration without addressing the sin that caused the judgment. The same YHWH who was the lion (5:14) and moth (5:12) is now expected to immediately restore — but without the &ldquo;acknowledgment of guilt&rdquo; specified in 5:15. This premature confidence in divine healing without genuine repentance is what YHWH finds insufficient.</p>",
        "2": "<p><strong>After two days he will revive us; on the third day he will raise us up, that we may live before him</strong> — the &ldquo;two days&hellip; third day&rdquo; formula is a common Hebrew idiom expressing a short, definite period (cf. Exod 19:11; Gen 22:4; 2 Kgs 20:5). Israel expects a speedy divine rescue after the Assyrian defeat. In its original context this is not predictive prophecy about Christ&rsquo;s resurrection but reflects the penitent&rsquo;s assumption that YHWH will quickly restore. However, the availability of this language in the OT canonical context is part of what Paul may mean by Christ rising &ldquo;on the third day in accordance with the Scriptures&rdquo; (1 Cor 15:4) — the resurrection fulfills the pattern of YHWH raising up his people, definitively and personally.</p>",
        "3": "<p><strong>Let us press on to know the LORD; his appearing is as certain as the dawn; he will come to us like the rain, like the spring rain that waters the earth</strong> — Israel compares YHWH&rsquo;s coming to the agricultural calendar&rsquo;s most reliable events: the dawn and the seasonal rains. The <em>yoreh</em> (early rain, autumn) and <em>malkosh</em> (spring rain) were the agricultural year&rsquo;s defining events, absolutely regular in the climate of Canaan. The problem YHWH identifies in v. 4 is that Israel treats his coming with the same predictable routine as the natural rains — a covenant relationship reduced to impersonal natural process, indistinguishable from the Baal cult it replaced.</p>",
        "4": "<p><strong>What shall I do with you, Ephraim? What shall I do with you, Judah? Your love is like a morning cloud, like the early dew that goes away</strong> — YHWH&rsquo;s first-person lament; the double &ldquo;what shall I do with you?&rdquo; expresses divine frustration rather than divine confusion. <strong>Morning cloud</strong> and <strong>early dew</strong> are images of the most transient phenomena in the Palestinian climate: the morning cloud burns off in the heat and the dew evaporates within hours. Israel&rsquo;s <em>hesed</em> (covenant loyalty) is as ephemeral as its own morning mist. The irony: in v. 3, Israel praised YHWH&rsquo;s coming as certain as the dawn; now YHWH uses dawn imagery to describe Israel&rsquo;s love as insubstantial as morning vapor.</p>",
        "5": "<p><strong>Therefore I have hewn them by the prophets; I have slain them by the words of my mouth, and my judgment goes out as light</strong> — the prophetic word is YHWH&rsquo;s primary instrument of discipline: the prophets have been cutting (<em>chatsavti</em>, hewed as one hews stone or wood) Israel with their oracles. The image positions prophetic proclamation as surgical: painful but purposeful, cutting away the corrupted tissue. <strong>My judgment goes out as light</strong> — the transparency and certainty of YHWH&rsquo;s verdict; in contrast to the morning cloud that disappears, YHWH&rsquo;s judgment shines clearly and does not evaporate.</p>",
        "6": "<p><strong>For I desire covenant loyalty (<em>hesed</em>) and not sacrifice; the knowledge of God (<em>daʿat ʾelohim</em>) rather than burnt offerings</strong> — the programmatic statement of prophetic theology: the priority of relational covenant faithfulness over cultic performance. This is not the abolition of sacrifice but the prophetic insistence that sacrifice without <em>hesed</em> is meaningless or counterproductive. The same principle appears in Samuel (&ldquo;to obey is better than sacrifice,&rdquo; 1 Sam 15:22), Isaiah (&ldquo;I cannot endure iniquity and solemn assembly,&rdquo; Isa 1:13), Amos (5:21-24), and Micah (6:6-8). Jesus quotes Hosea 6:6 twice — Matthew 9:13 (defending eating with sinners) and Matthew 12:7 (defending Sabbath grain-plucking) — making it the interpretive key to his critique of Pharisaic legalism.</p>",
        "7": "<p><strong>But like Adam they have transgressed the covenant; there they have dealt faithlessly with me</strong> — the reference to <strong>Adam</strong> (<em>keʾadam</em>) is either &ldquo;like Adam&rdquo; (the individual) or &ldquo;like mankind/human beings&rdquo; or &ldquo;at Adam&rdquo; (a place in the Jordan valley; cf. Josh 3:16). If the referent is the individual Adam, this may be the earliest explicit prophetic comparison of Israel&rsquo;s covenant sin to the primordial human covenant violation in Eden. The sin of eating the forbidden fruit is the paradigm for Israel&rsquo;s transgression of the Sinai covenant: both involve clear divine instruction, deliberate violation, and the forfeiting of the blessed conditions that obedience would have maintained.</p>",
        "8": "<p><strong>Gilead is a city of evildoers, stained with blood</strong> — Gilead, the Transjordanian territory east of the Jordan, had been a site of significant political violence in the later monarchy: the assassination of Zechariah son of Jeroboam II (2 Kgs 15:10, at Ibleam, near Gilead) and subsequent political instability. The description of a <strong>city</strong> (&ldquo;Gilead is a city of evildoers&rdquo;) may be a collective term for the region&rsquo;s population or may refer to a specific city (Ramoth-gilead or another Gileadite center) known for its violence.</p>",
        "9": "<p><strong>As raiders lie in wait for someone, so do bands of priests; they murder on the road to Shechem and commit the worst of crimes</strong> — Shechem was both a levitical city and a city of refuge (Josh 20:7; 21:21), where those guilty of manslaughter could find asylum. The irony is extreme: the priests who are supposed to provide sanctuary at the refuge city are instead ambushing travelers on the road to it. The priestly office has been completely inverted: instead of offering life, it takes it. This is the logical outcome of 4:8 (priests feeding on sin offerings — benefiting from iniquity).</p>",
        "10": "<p><strong>I have seen a horrible thing in the house of Israel: there Ephraim&rsquo;s prostitution is found; Israel is defiled</strong> — <em>shaʿaruryah</em> (&ldquo;horrible thing&rdquo;) is one of the strongest Hebrew terms of revulsion: something hair-raising, shocking to the moral sensibility. The word appears in Jeremiah 5:30 and 23:14 for the condition of the false prophets and Jerusalem; it signals a situation that has gone so far beyond normal corruption that it produces visceral horror. The naming of &ldquo;the house of Israel&rdquo; as the location of this horror contrasts bitterly with what the &ldquo;house of Israel&rdquo; was supposed to be — YHWH&rsquo;s dwelling place among his people.</p>",
        "11": "<p><strong>Also, O Judah, a harvest is appointed for you, when I restore the fortunes of my people</strong> — the dual message of the chapter&rsquo;s final verse: Judah will also face a harvest of judgment (the coming judgment, whether Assyrian or Babylonian), and yet the phrase <em>shavti shevut ammi</em> (&ldquo;when I restore the fortunes of my people&rdquo;) is the standard phrase of eschatological restoration (Jer 30:3; Ezek 39:25; Joel 3:1; Amos 9:14). The verse holds both judgment and hope simultaneously: the harvest Judah will reap is a judgment harvest, but the same frame of &ldquo;restoring fortunes&rdquo; that the prophets use for the great eschatological renewal is already present as the horizon toward which even this judgment is moving.</p>",
    },
}


def main():
    existing = load_comm("mkt-context", "hosea")
    merge_comm(existing, HOSEA)
    save_comm("mkt-context", "hosea", existing)
    print("Hosea 1–6 mkt-context written.")


if __name__ == "__main__":
    main()
